# Unit Tests for `reverse_words` Function

```python
import pytest


def reverse_words(s: str) -> str:
    return ' '.join(s.split()[::-1])


class TestReverseWords:
    """Test suite for the reverse_words function."""

    # Happy Path Tests
    def test_reverse_words_basic(self):
        """Test reversing a simple sentence with multiple words."""
        assert reverse_words("Hello World") == "World Hello"

    def test_reverse_words_three_words(self):
        """Test reversing a sentence with three words."""
        assert reverse_words("The quick brown") == "brown quick The"

    def test_reverse_words_single_word(self):
        """Test that a single word remains unchanged."""
        assert reverse_words("Hello") == "Hello"

    def test_reverse_words_preserves_word_content(self):
        """Test that individual words are not reversed, only their order."""
        assert reverse_words("abc def ghi") == "ghi def abc"

    # Edge Cases
    def test_reverse_words_empty_string(self):
        """Test reversing an empty string."""
        assert reverse_words("") == ""

    def test_reverse_words_only_spaces(self):
        """Test string with only whitespace."""
        assert reverse_words("   ") == ""

    def test_reverse_words_leading_spaces(self):
        """Test string with leading spaces."""
        assert reverse_words("   Hello World") == "World Hello"

    def test_reverse_words_trailing_spaces(self):
        """Test string with trailing spaces."""
        assert reverse_words("Hello World   ") == "World Hello"

    def test_reverse_words_multiple_spaces_between_words(self):
        """Test string with multiple spaces between words."""
        assert reverse_words("Hello    World") == "World Hello"

    def test_reverse_words_mixed_whitespace(self):
        """Test string with tabs and multiple spaces."""
        assert reverse_words("Hello\t\tWorld  Python") == "Python World Hello"

    def test_reverse_words_newlines_and_tabs(self):
        """Test string with newlines and tabs."""
        assert reverse_words("Hello\nWorld\tPython") == "Python World Hello"

    def test_reverse_words_two_words(self):
        """Test reversing exactly two words."""
        assert reverse_words("First Second") == "Second First"

    # Case Sensitivity Tests
    def test_reverse_words_mixed_case(self):
        """Test that case is preserved during reversal."""
        assert reverse_words("HeLLo WoRLd") == "WoRLd HeLLo"

    def test_reverse_words_all_uppercase(self):
        """Test with all uppercase words."""
        assert reverse_words("HELLO WORLD") == "WORLD HELLO"

    def test_reverse_words_all_lowercase(self):
        """Test with all lowercase words."""
        assert reverse_words("hello world") == "world hello"

    # Special Characters Tests
    def test_reverse_words_with_punctuation(self):
        """Test words containing punctuation."""
        assert reverse_words("Hello, World!") == "World! Hello,"

    def test_reverse_words_with_numbers(self):
        """Test words containing numbers."""
        assert reverse_words("abc123 def456") == "def456 abc123"

    def test_reverse_words_with_special_chars(self):
        """Test words with special characters."""
        assert reverse_words("hello@world.com test#case") == "test#case hello@world.com"

    # Unicode and International Characters
    def test_reverse_words_unicode(self):
        """Test with unicode characters."""
        assert reverse_words("café naïve") == "naïve café"

    def test_reverse_words_emoji(self):
        """Test with emoji characters."""
        assert reverse_words("hello 👋 world 🌍") == "🌍 world 👋 hello"

